/**
 * Lumo UI canonical commerce data model.
 *
 * Components are headless-agnostic: they consume these normalized shapes via
 * props. Map your backend (Shopify, Medusa, commercetools, custom) onto these
 * types once, and every Lumo block works against it.
 *
 * Money is stored in integer minor units (for example cents) to avoid
 * floating-point rounding errors. Use `formatMoney` to render it.
 */

/** ISO 4217 currency code, e.g. 'USD', 'EUR', 'JPY'. */
export type CurrencyCode = string

/**
 * A monetary amount in integer minor units plus its currency.
 *
 * @example { amount: 1999, currency: 'USD' } // represents $19.99
 * @example { amount: 500, currency: 'JPY' }  // represents ¥500 (JPY has 0 minor units)
 */
export interface Money {
  /** Integer amount in the currency's minor units (e.g. cents). */
  amount: number
  currency: CurrencyCode
}

export interface Image {
  url: string
  alt?: string
  width?: number
  height?: number
}

/** A configurable axis of a product, e.g. { name: 'Size', values: ['S','M','L'] }. */
export interface ProductOption {
  name: string
  values: string[]
}

/** A concrete option choice on a variant, e.g. { name: 'Size', value: 'M' }. */
export interface SelectedOption {
  name: string
  value: string
}

/** A purchasable variant of a product (a specific SKU / option combination). */
export interface Variant {
  id: string
  sku?: string
  title?: string
  price: Money
  /** Original price before discount; drives sale and compare-at display. */
  compareAtPrice?: Money
  selectedOptions: SelectedOption[]
  available: boolean
  inventoryQuantity?: number
  image?: Image
}

export interface ProductRating {
  /** Average rating value, typically 0 to 5. */
  value: number
  /** Number of reviews behind the rating. */
  count: number
}

export interface Product {
  id: string
  /** URL-friendly slug. */
  handle: string
  title: string
  description?: string
  images: Image[]
  options: ProductOption[]
  variants: Variant[]
  /** Id of the variant selected by default; falls back to the first available. */
  defaultVariantId?: string
  rating?: ProductRating
  /** Display badges, e.g. 'sale', 'new', 'limited', or custom labels. */
  badges?: string[]
  tags?: string[]
  vendor?: string
}

/** A line in the cart: a variant, its parent product summary, and a quantity. */
export interface CartLine {
  id: string
  variant: Variant
  product: Pick<Product, 'id' | 'handle' | 'title' | 'images'>
  quantity: number
  lineTotal: Money
}

export interface Cart {
  id?: string
  lines: CartLine[]
  currency: CurrencyCode
  subtotal: Money
  /**
   * Grand total. Optional because tax, shipping, and discount logic is owned
   * by your backend, not by Lumo components.
   */
  total?: Money
}

export interface Address {
  firstName: string
  lastName: string
  line1: string
  line2?: string
  city: string
  /** State or province. */
  region?: string
  postalCode: string
  /** ISO 3166-1 alpha-2 country code, e.g. 'US', 'FR'. */
  country: string
  phone?: string
}

import type { Money } from './types'

/**
 * Number of minor-unit digits for a currency, derived from Intl.
 * USD -> 2, JPY -> 0, BHD -> 3. Falls back to 2 if the runtime lacks the data.
 */
export function getCurrencyFractionDigits(currency: string): number {
  try {
    const resolved = new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency,
    }).resolvedOptions()
    return resolved.maximumFractionDigits ?? 2
  } catch {
    return 2
  }
}

/** Convert a Money amount from minor units to a major-unit decimal number. */
export function toMajorUnits(money: Money): number {
  const digits = getCurrencyFractionDigits(money.currency)
  return money.amount / 10 ** digits
}

/** Convert a major-unit decimal number to integer minor units. */
export function toMinorUnits(amount: number, currency: string): number {
  const digits = getCurrencyFractionDigits(currency)
  return Math.round(amount * 10 ** digits)
}

/**
 * Format a Money value as a localized currency string.
 *
 * @example formatMoney({ amount: 1999, currency: 'USD' }) // "$19.99"
 * @example formatMoney({ amount: 500, currency: 'JPY' }, { locale: 'ja-JP' }) // "￥500"
 */
export function formatMoney(
  money: Money,
  options: { locale?: string } & Omit<
    Intl.NumberFormatOptions,
    'style' | 'currency'
  > = {}
): string {
  const { locale, ...numberFormatOptions } = options
  return new Intl.NumberFormat(locale, {
    style: 'currency',
    currency: money.currency,
    ...numberFormatOptions,
  }).format(toMajorUnits(money))
}

/** Create a zero-value Money in the given currency. */
export function zeroMoney(currency: string): Money {
  return { amount: 0, currency }
}

/**
 * Add Money values. All inputs must share a currency, otherwise it throws,
 * because silently mixing currencies is a correctness bug.
 */
export function addMoney(...values: Money[]): Money {
  if (values.length === 0) {
    throw new Error('addMoney requires at least one value')
  }
  const [first] = values
  const { currency } = first
  let amount = 0
  for (const value of values) {
    if (value.currency !== currency) {
      throw new Error(
        `Cannot add Money of different currencies: ${currency} and ${value.currency}`
      )
    }
    amount += value.amount
  }
  return { amount, currency }
}

/** Multiply a Money value by an integer quantity (e.g. a line total). */
export function multiplyMoney(money: Money, quantity: number): Money {
  return { amount: Math.round(money.amount * quantity), currency: money.currency }
}

/** Discount percentage between an original and current price, 0 to 100. */
export function discountPercent(original: Money, current: Money): number {
  if (original.currency !== current.currency) {
    throw new Error(
      `Cannot compare Money of different currencies: ${original.currency} and ${current.currency}`
    )
  }
  if (original.amount <= 0 || current.amount >= original.amount) {
    return 0
  }
  return Math.round(((original.amount - current.amount) / original.amount) * 100)
}
